+/// `BlueBubbles` `iMessage` connector state.
+#[derive(Debug)]
+pub struct BlueBubblesConnector {
+    base: BaseConnector,
+    config: Option<BlueBubblesConfig>,
+    client: Option<BlueBubblesClient>,
+    runtime: Option<ConnectorRuntime>,
+    retry_config: HttpRetryConfig,
+    started_at: Instant,
+    verifier: Option<CapabilityVerifier>,
+}
+
+impl BlueBubblesConnector {
+    /// Create a new connector instance.
+    #[must_use]
+    pub fn new() -> Self {
+        Self {
+            base: BaseConnector::new(ConnectorId::from_static("fcp.imessage")),
+            config: None,
+            client: None,
+            runtime: None,
+            retry_config: HttpRetryConfig::default(),
+            started_at: Instant::now(),
+            verifier: None,
+        }
+    }
+
+    fn manifest_hash() -> String {
+        let mut hasher = Sha256::new();
+        hasher.update(MANIFEST_TOML.as_bytes());
+        format!("sha256:{}", hex::encode(hasher.finalize()))
+    }
+
+    /// Run connector diagnostics.
+    pub fn doctor(&self) -> DoctorResult {
+        let mut checks = Vec::new();
+
+        let configured = self.config.is_some();
+        checks.push(DoctorCheck {
+            name: "configuration".into(),
+            passed: configured,
+            message: Some(if configured {
+                "Configuration loaded".into()
+            } else {
+                "Not configured - run configure first".into()
+            }),
+            critical: true,
+        });
+
+        let client_ok = self.client.is_some();
+        checks.push(DoctorCheck {
+            name: "client_initialized".into(),
+            passed: client_ok,
+            message: Some(if client_ok {
+                "HTTP client initialized".into()
+            } else {
+                "HTTP client missing; re-run configure".into()
+            }),
+            critical: true,
+        });
+
+        let runtime_ok = self.runtime.is_some();
+        checks.push(DoctorCheck {
+            name: "runtime".into(),
+            passed: runtime_ok,
+            message: Some(if runtime_ok {
+                "ConnectorRuntime initialized".into()
+            } else {
+                "Runtime missing".into()
+            }),
+            critical: true,
+        });
+
+        if let Some(config) = &self.config {
+            let scheme = if config.server_url.starts_with("https://") {
+                "https"
+            } else {
+                "http"
+            };
+            checks.push(DoctorCheck {
+                name: "server_url".into(),
+                passed: true,
+                message: Some(format!("Server URL ({scheme}): {}", config.server_url)),
+                critical: false,
+            });
+
+            let host_part = config
+                .server_url
+                .split("://")
+                .nth(1)
+                .unwrap_or("")
+                .split('/')
+                .next()
+                .unwrap_or("")
+                .split(':')
+                .next()
+                .unwrap_or("");
+            let host_ok = host_part == "localhost" || host_part == "127.0.0.1";
+            checks.push(DoctorCheck {
+                name: "network_constraints".into(),
+                passed: host_ok,
+                message: Some(if host_ok {
+                    "Server URL is local (localhost or 127.0.0.1)".into()
+                } else {
+                    format!("Server URL host '{host_part}' is not localhost; ensure trust boundary")
+                }),
+                critical: false,
+            });
+
+            let password_ok = !config.password.is_empty();
+            checks.push(DoctorCheck {
+                name: "password".into(),
+                passed: password_ok,
+                message: Some(if password_ok {
+                    "Password is set".into()
+                } else {
+                    "Password is empty".into()
+                }),
+                critical: true,
+            });
+        }
+
+        DoctorResult::from_checks(checks)
+    }
+}
+
+impl Default for BlueBubblesConnector {
+    fn default() -> Self {
+        Self::new()
+    }
+}
