+    /// Validate the selected authentication mode.
+    pub fn validate(&self) -> FcpResult<()> {
+        match self {
+            Self::Basic { username, password } => {
+                validate_non_empty("auth.username", username)?;
+                validate_non_empty("auth.password", password)?;
+            }
+            Self::AppPassword {
